function debounce(fn, delay=300){
  let t;
  return (...a) => {
    clearTimeout(t);
    t = setTimeout(() => fn(...a), delay);
  };
}

function throttle(fn, limit=300){
  let wait;
  return (...a) => {
    if (!wait) { fn(...a); wait = true;
      setTimeout(() => wait = false, limit); }
  };
}
